import { jsPDF } from 'jspdf'

// ── Paste your logo base64 here ───────────────────────────────────────────────
// This is the actual Alan Mens Wear logo (JPEG, base64 encoded)
const LOGO_BASE64 = `

`

const colors = {
  dark: '#10161d',
  darker: '#0b1015',
  gold: '#b77a25',
  goldLight: '#e2bd78',
  ink: '#111827',
  border: '#dfc394',
  softGold: '#fff8ec',
  line: '#d8dde4',
}

const company = {
  name: 'Alan Mens Wear',
  address: ['2/2024, South Street,', 'Sivakasi, Tamil Nadu,', 'India'],
  phone: '+91 9360436527',
  email: 'support@alanmenswear.com',
  website: 'https://alanmenswear.netlify.app/',
  instagram: '@alanmenswear',
}

const formatCurrency = (amount) => `Rs. ${Number(amount || 0).toLocaleString('en-IN')}`

const formatDate = (value) => {
  const date = value?.toDate?.() || value || new Date()
  return new Date(date).toLocaleDateString('en-IN')
}

function hex2rgb(hex) {
  return [
    parseInt(hex.slice(1, 3), 16),
    parseInt(hex.slice(3, 5), 16),
    parseInt(hex.slice(5, 7), 16),
  ]
}

function setFill(doc, color) { doc.setFillColor(...hex2rgb(color)) }
function setDraw(doc, color) { doc.setDrawColor(...hex2rgb(color)) }
function setTextColor(doc, color) { doc.setTextColor(...hex2rgb(color)) }

// ── Header with real logo image ───────────────────────────────────────────────
function drawHeader(doc, pageWidth) {
  // Dark background
  setFill(doc, colors.darker)
  doc.rect(10, 8, pageWidth - 20, 58, 'F')

  // Gold bottom accent bar
  setFill(doc, colors.gold)
  doc.rect(10, 66, pageWidth - 20, 1.5, 'F')

  // Real logo image — white bg crop so it sits on dark header
  try {
    doc.addImage(
      'data:image/jpeg;base64,' + LOGO_BASE64,
      'JPEG',
      14,        // x
      9,         // y
      52,        // width
      56,        // height (keeps aspect ratio)
    )
  } catch {
    // Fallback text if image fails
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(18)
    setTextColor(doc, '#ffffff')
    doc.text('ALAN', 18, 42)
  }

  // Vertical divider
  setDraw(doc, '#555555')
  doc.setLineWidth(0.3)
  doc.line(72, 16, 72, 58)

  // Company name text next to logo
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(13)
  setTextColor(doc, '#ffffff')
  doc.text('ALAN', 78, 30)

  doc.setFontSize(7)
  setTextColor(doc, colors.goldLight)
  doc.text('MENS WEAR', 78, 38)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(5)
  setTextColor(doc, '#aaaaaa')
  doc.text('DRESS BETTER. FEEL CONFIDENT.', 78, 45)

  // Second vertical divider before INVOICE
  setDraw(doc, '#555555')
  doc.setLineWidth(0.3)
  doc.line(118, 16, 118, 58)

  // INVOICE label
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(22)
  setTextColor(doc, '#ffffff')
  doc.text('INVOICE', pageWidth - 22, 32, { align: 'right' })

  // Gold accent lines
  setDraw(doc, colors.gold)
  doc.setLineWidth(0.5)
  doc.line(pageWidth - 62, 37, pageWidth - 22, 37)
  doc.line(pageWidth - 62, 40, pageWidth - 22, 40)
}

// ── Detail row ────────────────────────────────────────────────────────────────
function drawDetailRow(doc, icon, label, value, y) {
  setFill(doc, colors.softGold)
  setDraw(doc, colors.border)
  doc.setLineWidth(0.5)
  doc.circle(25, y - 2.5, 5, 'FD')

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(8)
  setTextColor(doc, colors.gold)
  doc.text(icon, 25, y + 0.5, { align: 'center' })

  doc.setFontSize(8)
  setTextColor(doc, colors.gold)
  doc.text(label, 35, y - 5)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(10)
  setTextColor(doc, colors.ink)
  doc.text(String(value || '-'), 35, y + 3)
}

// ── Thank-you box ─────────────────────────────────────────────────────────────
function drawThankYouBox(doc, pageWidth, y) {
  const boxW = 68
  const x = pageWidth - 18 - boxW

  setFill(doc, '#fffaf2')
  setDraw(doc, colors.border)
  doc.setLineWidth(0.5)
  doc.roundedRect(x, y, boxW, 32, 2, 2, 'FD')

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(10)
  setTextColor(doc, colors.ink)
  doc.text('Thank you', x + boxW / 2, y + 10, { align: 'center' })
  doc.text('for shopping with', x + boxW / 2, y + 18, { align: 'center' })
  doc.setFont('helvetica', 'bold')
  doc.text('Alan Mens Wear.', x + boxW / 2, y + 26, { align: 'center' })
}

// ── Table header ──────────────────────────────────────────────────────────────
function drawTableHeader(doc, y, pageWidth) {
  setFill(doc, colors.dark)
  doc.roundedRect(18, y, pageWidth - 36, 10, 1, 1, 'F')

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(9)
  setTextColor(doc, '#ffffff')
  doc.text('PRODUCT NAME', 25, y + 6.8)
  doc.text('QTY', 113, y + 6.8, { align: 'center' })
  doc.text('AMOUNT', pageWidth - 25, y + 6.8, { align: 'right' })
}

// ── Total bar ─────────────────────────────────────────────────────────────────
function drawTotal(doc, y, pageWidth, totalAmount) {
  const totalWidth = 90
  const x = pageWidth - 18 - totalWidth

  setFill(doc, '#fff7e8')
  setDraw(doc, colors.border)
  doc.setLineWidth(0.5)
  doc.rect(x, y, totalWidth / 2, 12, 'FD')

  setFill(doc, colors.gold)
  doc.rect(x + totalWidth / 2, y, totalWidth / 2, 12, 'F')

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(9)
  setTextColor(doc, colors.ink)
  doc.text('TOTAL AMOUNT', x + totalWidth / 4, y + 7.8, { align: 'center' })

  doc.setFontSize(11)
  setTextColor(doc, '#ffffff')
  doc.text(formatCurrency(totalAmount), x + totalWidth - 4, y + 7.8, { align: 'right' })
}

// ── Footer ────────────────────────────────────────────────────────────────────
function drawFooter(doc, pageWidth, pageHeight) {
  const y = pageHeight - 52

  setDraw(doc, colors.border)
  doc.setLineWidth(0.5)
  doc.line(18, y, pageWidth - 18, y)

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(9)
  setTextColor(doc, colors.gold)
  doc.text('Location', 38, y + 9, { align: 'center' })
  doc.text('Contact', pageWidth / 2, y + 9, { align: 'center' })
  doc.text('Online', pageWidth - 38, y + 9, { align: 'center' })

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  setTextColor(doc, colors.ink)
  doc.text(company.name, 38, y + 16, { align: 'center' })
  doc.text(company.address, 38, y + 22, { align: 'center' })
  doc.text(company.phone, pageWidth / 2, y + 19, { align: 'center' })
  doc.text(company.email, pageWidth / 2, y + 27, { align: 'center' })
  doc.text(company.website, pageWidth - 38, y + 19, { align: 'center' })
  doc.text(company.instagram, pageWidth - 38, y + 27, { align: 'center' })

  setDraw(doc, colors.line)
  doc.setLineWidth(0.3)
  doc.line(65, y + 5, 65, y + 32)
  doc.line(pageWidth - 65, y + 5, pageWidth - 65, y + 32)

  // Bottom strip
  setDraw(doc, colors.border)
  doc.setLineWidth(0.4)
  doc.line(18, pageHeight - 10, 84, pageHeight - 10)
  doc.line(pageWidth - 84, pageHeight - 10, pageWidth - 18, pageHeight - 10)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  setTextColor(doc, colors.ink)
  doc.text('Thank you for choosing Alan Mens Wear!', pageWidth / 2, pageHeight - 4, {
    align: 'center',
  })
}

// ── Page frame ────────────────────────────────────────────────────────────────
function drawPageFrame(doc, pageWidth, pageHeight) {
  setDraw(doc, '#eef0f3')
  doc.setLineWidth(0.5)
  doc.roundedRect(8, 6, pageWidth - 16, pageHeight - 12, 2, 2, 'S')
}

// ── MAIN EXPORT ───────────────────────────────────────────────────────────────
export function downloadInvoice(order) {
  const doc = new jsPDF()
  const pageWidth  = doc.internal.pageSize.getWidth()
  const pageHeight = doc.internal.pageSize.getHeight()

  drawPageFrame(doc, pageWidth, pageHeight)
  drawHeader(doc, pageWidth)

  drawDetailRow(doc, '#', 'Order ID',      order.id,                            92)
  drawDetailRow(doc, '@', 'Customer Name', order.customerName || 'Customer',   110)
  drawDetailRow(doc, 'D', 'Date',          formatDate(order.createdAt),         128)

  drawThankYouBox(doc, pageWidth, 88)

  let y = 150
  drawTableHeader(doc, y, pageWidth)
  y += 18

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(10)
  setTextColor(doc, colors.ink)

  order.items?.forEach((item) => {
    if (y > pageHeight - 80) {
      doc.addPage()
      drawPageFrame(doc, pageWidth, pageHeight)
      drawHeader(doc, pageWidth)
      y = 80
      drawTableHeader(doc, y, pageWidth)
      y += 18
    }

    const lineTotal    = Number(item.price || 0) * Number(item.quantity || 0)
    const productLines = doc.splitTextToSize(item.name, 80)

    doc.text(productLines, 25, y)
    doc.text(String(item.quantity), 113, y, { align: 'center' })
    doc.text(formatCurrency(lineTotal), pageWidth - 25, y, { align: 'right' })

    y += Math.max(productLines.length * 5.5, 10)
    setDraw(doc, colors.line)
    doc.setLineDashPattern([1.5, 1.5], 0)
    doc.line(18, y, pageWidth - 18, y)
    doc.setLineDashPattern([], 0)
    y += 8
  })

  y = Math.max(y + 4, 192)
  drawTotal(doc, y, pageWidth, order.totalAmount)
  drawFooter(doc, pageWidth, pageHeight)

  doc.save(`alan-mens-wear-invoice-${order.id.slice(0, 8)}.pdf`)
}
